import React, { useEffect, useState } from "react";
import API from "../../api/api";

const CATS = [
  { value:"", label:"All" },
  { value:"web-development", label:"Web Development" },
  { value:"mobile-development", label:"Mobile" },
  { value:"ui-ux-design", label:"UI/UX" },
  { value:"graphic-design", label:"Graphic Design" },
  { value:"backend-development", label:"Backend" },
  { value:"data-science", label:"Data Science" },
  { value:"devops-cloud", label:"DevOps" },
  { value:"content-writing", label:"Content" },
  { value:"digital-marketing", label:"Marketing" },
  { value:"other", label:"Other" },
];
const fmt = (d) => d ? new Date(d).toLocaleDateString("en-IN",{day:"2-digit",month:"short",year:"numeric"}) : "";

export default function FindProjects() {
  const [projects, setProjects] = useState([]);
  const [search, setSearch] = useState("");
  const [cat, setCat] = useState("");
  const [appliedIds, setAppliedIds] = useState([]);
  const [modal, setModal] = useState(null);
  const [form, setForm] = useState({ bid:"", message:"" });
  const [submitting, setSubmitting] = useState(false);
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    Promise.all([API.get("/projects"), API.get("/proposals/my")]).then(([pr, my]) => {
      setProjects(pr.data || []);
      setAppliedIds((my.data || []).map(p => p.project_id));
      setLoading(false);
    }).catch(() => setLoading(false));
  }, []);

  const filtered = projects.filter(p => {
    const q = search.toLowerCase();
    return (!q || p.title?.toLowerCase().includes(q) || p.description?.toLowerCase().includes(q))
      && (!cat || p.category === cat);
  });

  const submit = async () => {
    if (!form.bid || !form.message) return alert("Fill all fields");
    setSubmitting(true);
    try {
      await API.post("/proposals", { project_id: modal.id, bid: form.bid, message: form.message });
      setAppliedIds(prev => [...prev, modal.id]);
      setModal(null); setForm({ bid:"", message:"" });
    } catch(e) { alert(e.response?.data?.message || "Error"); }
    setSubmitting(false);
  };

  if (loading) return <div style={{ background:"#f8fafc", minHeight:"100vh", display:"flex", alignItems:"center", justifyContent:"center" }}><span style={{ color:"#0f766e", fontWeight:"600" }}>Loading...</span></div>;

  return (
    <div style={{ background:"#f8fafc", minHeight:"100vh", padding:"32px", fontFamily:"'Segoe UI',sans-serif" }}>
      <h1 style={{ fontSize:"24px", fontWeight:"700", color:"#0f172a", margin:"0 0 4px" }}>Find Projects</h1>
      <p style={{ color:"#64748b", fontSize:"13px", marginBottom:"24px" }}>Browse available projects and submit your proposals</p>

      {/* SEARCH */}
      <input
        style={{ width:"100%", padding:"11px 16px", border:"1px solid #e2e8f0", borderRadius:"10px", fontSize:"14px", outline:"none", background:"white", color:"#0f172a", boxSizing:"border-box", marginBottom:"16px", boxShadow:"0 1px 3px rgba(0,0,0,0.04)" }}
        placeholder="Search by title or description..."
        value={search} onChange={e => setSearch(e.target.value)}
      />

      {/* CATEGORY FILTER */}
      <div style={{ display:"flex", gap:"8px", flexWrap:"wrap", marginBottom:"24px" }}>
        {CATS.map(c => (
          <button key={c.value} onClick={() => setCat(c.value)}
            style={{ padding:"6px 14px", borderRadius:"20px", fontSize:"12px", fontWeight:"600", cursor:"pointer", border: cat===c.value ? "none" : "1px solid #e2e8f0", background: cat===c.value ? "#0f766e" : "white", color: cat===c.value ? "white" : "#64748b", transition:"all 0.15s" }}>
            {c.label}
          </button>
        ))}
      </div>

      {/* GRID */}
      {filtered.length === 0 ? (
        <div style={{ textAlign:"center", padding:"60px", color:"#94a3b8" }}>
          <div style={{ fontSize:"40px", marginBottom:"12px" }}>📭</div>
          <p>No projects found</p>
        </div>
      ) : (
        <div style={{ display:"grid", gridTemplateColumns:"repeat(auto-fill, minmax(360px,1fr))", gap:"16px" }}>
          {filtered.map(p => {
            const applied = appliedIds.includes(p.id);
            return (
              <div key={p.id} style={{ background:"white", border:"1px solid #e2e8f0", borderRadius:"14px", padding:"22px", boxShadow:"0 1px 4px rgba(0,0,0,0.04)", transition:"box-shadow 0.2s" }}>
                <div style={{ display:"flex", justifyContent:"space-between", alignItems:"flex-start", marginBottom:"8px" }}>
                  <h3 style={{ fontSize:"16px", fontWeight:"700", color:"#0f172a", margin:0 }}>{p.title}</h3>
                  <span style={{ background:"#dcfce7", color:"#16a34a", fontSize:"10px", fontWeight:"700", padding:"3px 10px", borderRadius:"20px", flexShrink:0, marginLeft:"8px" }}>{p.status || "Open"}</span>
                </div>
                <p style={{ fontSize:"13px", color:"#64748b", marginBottom:"14px", lineHeight:1.5 }}>{p.description?.slice(0,100)}...</p>
                {p.skills && (
                  <div style={{ display:"flex", gap:"6px", flexWrap:"wrap", marginBottom:"12px" }}>
                    {p.skills.split(",").slice(0,4).map((s,i) => (
                      <span key={i} style={{ background:"#f0fdf9", color:"#0f766e", border:"1px solid #99f6e4", borderRadius:"6px", padding:"3px 10px", fontSize:"11px", fontWeight:"600" }}>{s.trim()}</span>
                    ))}
                  </div>
                )}
                <div style={{ display:"flex", gap:"14px", fontSize:"12px", color:"#94a3b8", marginBottom:"14px" }}>
                  {p.deadline && <span>📅 {fmt(p.deadline)}</span>}
                  {p.proposals_count !== undefined && <span>📄 {p.proposals_count} proposals</span>}
                  {p.category && <span style={{ color:"#0f766e", fontWeight:"600" }}>{p.category.replace(/-/g," ")}</span>}
                </div>
                <p style={{ fontSize:"20px", fontWeight:"800", color:"#0f766e", margin:"0 0 14px" }}>₹{p.budget}</p>
                {applied
                  ? <button style={{ width:"100%", padding:"10px", borderRadius:"9px", border:"1px solid #bbf7d0", background:"#f0fdf4", color:"#16a34a", fontSize:"13px", fontWeight:"700", cursor:"default" }}>✓ Applied</button>
                  : <button onClick={() => { setModal(p); setForm({ bid:"", message:"" }); }}
                      style={{ width:"100%", padding:"10px", borderRadius:"9px", border:"none", background:"linear-gradient(135deg,#0f766e,#0891b2)", color:"white", fontSize:"13px", fontWeight:"700", cursor:"pointer" }}>
                      Apply Now
                    </button>
                }
              </div>
            );
          })}
        </div>
      )}

      {/* MODAL */}
      {modal && (
        <div style={{ position:"fixed", inset:0, background:"rgba(15,23,42,0.5)", display:"flex", alignItems:"center", justifyContent:"center", zIndex:50, padding:"20px" }}
          onClick={e => e.target === e.currentTarget && setModal(null)}>
          <div style={{ background:"white", borderRadius:"16px", padding:"28px", width:"100%", maxWidth:"440px", boxShadow:"0 20px 60px rgba(0,0,0,0.15)" }}>
            <h2 style={{ fontSize:"18px", fontWeight:"700", color:"#0f172a", margin:"0 0 4px" }}>Submit Proposal</h2>
            <p style={{ fontSize:"12px", color:"#64748b", marginBottom:"20px" }}>{modal.title} · Budget: ₹{modal.budget}</p>
            <label style={{ fontSize:"11px", fontWeight:"700", color:"#64748b", display:"block", marginBottom:"4px", textTransform:"uppercase", letterSpacing:"0.8px" }}>Your Bid (₹)</label>
            <input type="number" placeholder="Enter your bid amount" value={form.bid} onChange={e=>setForm({...form,bid:e.target.value})}
              style={{ width:"100%", padding:"10px 12px", border:"1.5px solid #e2e8f0", borderRadius:"8px", fontSize:"13px", outline:"none", boxSizing:"border-box", marginBottom:"14px", color:"#0f172a" }} />
            <label style={{ fontSize:"11px", fontWeight:"700", color:"#64748b", display:"block", marginBottom:"4px", textTransform:"uppercase", letterSpacing:"0.8px" }}>Cover Letter</label>
            <textarea placeholder="Why are you the best fit?" value={form.message} onChange={e=>setForm({...form,message:e.target.value})}
              style={{ width:"100%", padding:"10px 12px", border:"1.5px solid #e2e8f0", borderRadius:"8px", fontSize:"13px", outline:"none", boxSizing:"border-box", marginBottom:"18px", height:"90px", resize:"none", color:"#0f172a" }} />
            <div style={{ display:"flex", gap:"10px" }}>
              <button onClick={submit} disabled={submitting}
                style={{ flex:1, padding:"11px", borderRadius:"9px", border:"none", background:"linear-gradient(135deg,#0f766e,#0891b2)", color:"white", fontWeight:"700", cursor:"pointer", opacity:submitting?.7:1 }}>
                {submitting ? "Submitting..." : "Submit Proposal"}
              </button>
              <button onClick={() => setModal(null)}
                style={{ padding:"11px 18px", borderRadius:"9px", border:"1px solid #e2e8f0", background:"white", color:"#64748b", cursor:"pointer" }}>
                Cancel
              </button>
            </div>
          </div>
        </div>
      )}
    </div>
  );
}
